import { useState } from "react";
import { Link, useRouter } from "expo-router";
import { Controller, useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { createMobileSession, fetchMe } from "@serrale/api";
import { clearSession, setSession } from "@serrale/auth";
import {
  AppButton,
  AppCard,
  AppInput,
  colors,
  spacing,
  typography
} from "@serrale/ui";
import { Pressable, StyleSheet, Text, View } from "react-native";
import { z } from "zod";

const signupSchema = z
  .object({
    fullName: z.string().min(2, "Enter your full name"),
    email: z.string().email("Enter a valid email address"),
    phone: z.string().min(8, "Enter a valid phone number"),
    password: z.string().min(6, "Password must be at least 6 characters"),
    confirmPassword: z.string().min(6, "Confirm your password")
  })
  .refine((data) => data.password === data.confirmPassword, {
    message: "Passwords do not match",
    path: ["confirmPassword"]
  });

type SignupValues = z.infer<typeof signupSchema>;

const preferenceOptions = [
  "Design",
  "Development",
  "Home Services",
  "Marketing",
  "IT Support",
  "Cleaning"
] as const;

export default function SignupScreen() {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showPreferences, setShowPreferences] = useState(false);
  const [selectedPreferences, setSelectedPreferences] = useState<string[]>([]);

  const { control, handleSubmit } = useForm<SignupValues>({
    resolver: zodResolver(signupSchema),
    defaultValues: {
      fullName: "",
      email: "",
      phone: "",
      password: "",
      confirmPassword: ""
    }
  });

  const togglePreference = (value: string) => {
    setSelectedPreferences((current) =>
      current.includes(value)
        ? current.filter((item) => item !== value)
        : [...current, value]
    );
  };

  const onSubmit = handleSubmit(async (values) => {
    try {
      setLoading(true);
      setError(null);

      const session = await createMobileSession({
        email: values.email,
        password: values.password,
        intent: "signup"
      });

      await setSession({
        accessToken: session.access_token,
        refreshToken: session.refresh_token
      });

      const me = await fetchMe();

      if (me.user.role !== "client") {
        await clearSession();
        setError("This account belongs to a service provider. Please use the Provider app.");
        return;
      }

      setShowPreferences(true);
    } catch (signupError) {
      setError(
        signupError instanceof Error
          ? signupError.message
          : "Unable to create account right now."
      );
    } finally {
      setLoading(false);
    }
  });

  if (showPreferences) {
    return (
      <View style={styles.screen}>
        <Text style={styles.title}>What do you need help with?</Text>
        <View style={styles.preferences}>
          {preferenceOptions.map((option) => {
            const selected = selectedPreferences.includes(option);

            return (
              <Pressable
                key={option}
                onPress={() => togglePreference(option)}
                style={[styles.preferenceChip, selected ? styles.preferenceChipSelected : null]}
              >
                <Text
                  style={[
                    styles.preferenceText,
                    selected ? styles.preferenceTextSelected : null
                  ]}
                >
                  {option}
                </Text>
              </Pressable>
            );
          })}
        </View>
        <AppButton label="Continue" onPress={() => router.replace("/tabs/home")} />
        <AppButton
          label="Skip for now"
          variant="secondary"
          onPress={() => router.replace("/tabs/home")}
        />
      </View>
    );
  }

  return (
    <View style={styles.screen}>
      <Text style={styles.logo}>SERRALE</Text>
      <Text style={styles.title}>Create your client account</Text>
      <Text style={styles.subtitle}>
        Post projects, find verified experts, and manage your bookings.
      </Text>
      <AppCard style={styles.formCard}>
        <Controller
          name="fullName"
