import { useState } from "react";
import { Link, useRouter } from "expo-router";
import { Controller, useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { createMobileSession, logoutMobileSession } from "@serrale/api";
import { setSession } from "@serrale/auth";
import {
  AppButton,
  AppCard,
  AppInput,
  colors,
  spacing,
  typography
} from "@serrale/ui";
import { StyleSheet, Text, View } from "react-native";
import { z } from "zod";

const loginSchema = z.object({
  email: z.string().email("Enter a valid email address"),
  password: z.string().min(6, "Password must be at least 6 characters")
});

type LoginValues = z.infer<typeof loginSchema>;

export default function LoginScreen() {
  const router = useRouter();
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const { control, handleSubmit } = useForm<LoginValues>({
    resolver: zodResolver(loginSchema),
    defaultValues: {
      email: "",
      password: ""
    }
  });

  const onSubmit = handleSubmit(async (values) => {
    try {
      setLoading(true);
      setError(null);

      const session = await createMobileSession({ ...values, intent: "login" });
      await setSession({
        accessToken: session.access_token,
        refreshToken: session.refresh_token
      });

      router.replace("/auth/role-validation");
    } catch (submissionError) {
      await logoutMobileSession().catch(() => undefined);
      setError(
        submissionError instanceof Error
          ? submissionError.message
          : "Unable to sign in right now."
      );
    } finally {
      setLoading(false);
    }
  });

  return (
    <View style={styles.screen}>
      <Text style={styles.logo}>SERRALE</Text>
      <Text style={styles.title}>Find trusted professionals</Text>
      <Text style={styles.subtitle}>Book verified experts for your next project.</Text>
      <AppCard style={styles.formCard}>
        <Controller
          name="email"
          control={control}
          render={({ field, fieldState }) => (
            <AppInput
              label="Email address"
              autoCapitalize="none"
              keyboardType="email-address"
              value={field.value}
              onChangeText={field.onChange}
              error={fieldState.error?.message}
            />
          )}
        />
        <Controller
          name="password"
          control={control}
          render={({ field, fieldState }) => (
            <AppInput
              label="Password"
              secureTextEntry
              value={field.value}
              onChangeText={field.onChange}
              error={fieldState.error?.message}
            />
          )}
        />
        <Link href="/auth/forgot-password" style={styles.forgot}>
          Forgot password?
        </Link>
        {error ? <Text style={styles.error}>{error}</Text> : null}
        <AppButton
          label={loading ? "Logging In..." : "Log In"}
          disabled={loading}
          onPress={onSubmit}
        />
        <View style={styles.separator}>
          <View style={styles.line} />
          <Text style={styles.separatorText}>or continue with</Text>
          <View style={styles.line} />
        </View>
        <AppButton
          label="Continue with Google"
          variant="secondary"
          onPress={() => setError("Google sign-in will be connected to backend auth next.")}
        />
      </AppCard>
      <Text style={styles.footer}>
        New to SERRALE?{" "}
        <Link href="/auth/signup" style={styles.footerLink}>
          Create an account
        </Link>
      </Text>
    </View>
  );
}

