import { useRouter } from "expo-router";
import { useQuery } from "@tanstack/react-query";
import { fetchMe } from "@serrale/api";
import { clearSession } from "@serrale/auth";
import { AppButton, LoadingScreen, colors, spacing, typography } from "@serrale/ui";
import { StyleSheet, Text, View } from "react-native";

export default function RoleValidationScreen() {
  const router = useRouter();
  const roleCheck = useQuery({
    queryKey: ["role-validation"],
    queryFn: fetchMe
  });

  if (roleCheck.isPending) {
    return <LoadingScreen message="Preparing your account..." />;
  }

  if (roleCheck.isError) {
    return (
      <View style={styles.screen}>
        <Text style={styles.title}>Unable to verify account</Text>
        <Text style={styles.message}>Please sign in again.</Text>
        <AppButton
          label="Use another account"
          onPress={async () => {
            await clearSession();
            router.replace("/auth/login");
          }}
        />
      </View>
    );
  }

  if (roleCheck.data.user.role === "service_provider") {
    return (
      <View style={styles.screen}>
        <Text style={styles.title}>This account belongs to a service provider</Text>
        <Text style={styles.message}>
          Please use the SERRALE Provider app to manage jobs and proposals.
        </Text>
        <View style={styles.actions}>
          <AppButton
            label="Open Provider App"
            onPress={() => {
              router.replace("/auth/login");
            }}
          />
          <AppButton
            label="Use another account"
            variant="secondary"
            onPress={async () => {
              await clearSession();
              router.replace("/auth/login");
            }}
          />
        </View>
      </View>
    );
  }

  if (roleCheck.data.user.role !== "client") {
    return <LoadingScreen message="Preparing your account..." />;
  }

  router.replace("/tabs/home");
  return <LoadingScreen message="Preparing your account..." />;
}

